import request from '@/utils/request'

// 档案数据管理
const profile = {
  // 获取完整档案数据
  getData() {
    console.log('获取完整档案数据')
    return request.get('/api/v1/users/profile/data/')
  },

  // 获取简历完整度
  getCompleteness() {
    console.log('获取简历完整度')
    return request.get('/api/v1/users/profile/completeness/')
  },

  // 上传头像
  uploadAvatar(formData) {
    console.log('上传头像')
    return request({
      url: '/api/v1/users/profile/data/basic_info/avatar/',
      method: 'post',
      headers: {
        'Content-Type': 'multipart/form-data'
      },
      data: formData
    })
  },

  // 获取布局配置
  getLayout() {
    console.log('获取布局配置')
    return request.get('/api/v1/users/profile/layout/')
  },

  // 更新布局配置
  updateLayout(data) {
    console.log('更新布局配置:', data)
    return request({
      url: '/api/v1/users/profile/layout/',
      method: 'put',
      data
    })
  },

  // 更新模块数据
  updateModule(type, data) {
    console.log('更新模块数据:', { type, data })
    // 如果是基本信息，使用完整档案接口
    if (type === 'basic_info') {
      // 先获取当前完整数据
      return request.get('/api/v1/users/profile/data/').then(response => {
        const currentData = response.data.data
        // 保留当前的 basic_info 数据，只更新提交的字段
        const currentBasicInfo = currentData.basic_info || {}
        const submitData = {
          basic_info: {
            ...currentBasicInfo,  // 保留所有现有字段
            // 只更新提交的字段
            name: data.name || currentBasicInfo.name,
            gender: data.gender || currentBasicInfo.gender,
            birth_date: data.birth_date || currentBasicInfo.birth_date,
            phone: data.phone || currentBasicInfo.phone,
            email: data.email || currentBasicInfo.email,
            location: data.location || currentBasicInfo.location,
            personal_summary: data.personal_summary || currentBasicInfo.personal_summary
          },
        }

        console.log('提交的数据:', submitData)

        return request({
          url: '/api/v1/users/profile/data/',
          method: 'put',
          params: { module_type: 'basic_info' },
          data: submitData
        })
      })
    }
    // 其他模块使用原有接口
    return request({
      url: `/api/v1/users/profile/data/${type}/`,
      method: 'put',
      data
    })
  },

  // 添加模块项目
  addModuleItem(type, data) {
    console.log('添加模块项目:', { type, data })
    return request({
      url: `/api/v1/users/profile/data/${type}/`,
      method: 'post',
      data
    })
  },

  // 删除模块项目
  deleteModuleItem(type, id) {
    console.log('删除模块项目:', { type, id })
    return request({
      url: `/api/v1/users/profile/data/${type}/${id}/`,
      method: 'delete'
    })
  }
}

// 导出 profile 对象
export default profile
